function solve(nums: number[]): number {
    let maxSum = -Infinity;
    const n = nums.length;

    for (let l = 0; l < n; l++) {
        let p = l;
        while (p + 1 < n && nums[p + 1] > nums[p]) {
            p++;
        }

        let q = p;
        while (q + 1 < n && nums[q + 1] < nums[q]) {
            q++;
        }

        let r = q;
        while (r + 1 < n && nums[r + 1] > nums[r]) {
            r++;
        }

        if (p > l && q > p && r > q) {
            let currentSum = 0;
            for (let i = l; i <= r; i++) {
                currentSum += nums[i];
            }
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    return maxSum;
}
